import React, { useEffect, useState } from 'react';
import {
    Dialog, DialogTitle, DialogContent,
    Box, Typography, CircularProgress, Alert, Divider, Chip, Stack, IconButton
} from '@mui/material';
import { ConfirmDialog } from '@/components/ui/ConfirmDialog';
import { logger } from '@/utils/logger';
import { getApiError } from '@/utils/apiError';
import CloseIcon from '@mui/icons-material/Close';
import PersonIcon from '@mui/icons-material/Person';
import EmailIcon from '@mui/icons-material/Email';
import PhoneIcon from '@mui/icons-material/Phone';
import PlaceIcon from '@mui/icons-material/Place';
import WorkIcon from '@mui/icons-material/Work';
import SchoolIcon from '@mui/icons-material/School';
import LocalLibraryIcon from '@mui/icons-material/LocalLibrary';
import BadgeIcon from '@mui/icons-material/Badge';
import CalendarTodayIcon from '@mui/icons-material/CalendarToday';
import EditIcon from '@mui/icons-material/Edit';
import AdminPanelSettingsIcon from '@mui/icons-material/AdminPanelSettings';
import LocationOnIcon from '@mui/icons-material/LocationOn';
import SecurityIcon from '@mui/icons-material/Security';
import LinkIcon from '@mui/icons-material/Link';
import { ProfileServices, ProfileServicesError } from '@/api';
import { PublicProfileResult, ProfileResult } from '@/types/profile.types';
import { CallStatus, Roles, Validator } from '@/types/api.types';
import { GetUserId, GetUserRoles } from '@/utils/token';
import { useBodyScrollLock } from '@/hooks/useBodyScrollLock';
import { useNavigate } from '@tanstack/react-router';
import DeleteIcon from '@mui/icons-material/Delete';
import LockResetIcon from '@mui/icons-material/LockReset';
import UpdateRoleDialog, { RoleDialogProfile } from '@/pages/role/components/UpdateRoleDialog';
import { AuthServices, AuthServicesError } from '@/api';

type ProfileInfoMode = 'public' | 'admin';

interface ProfileInfoDialogProps {
    open: boolean;
    profileId: string;
    mode: ProfileInfoMode;
    onClose: () => void;
}

const DetailRow: React.FC<{ icon: React.ReactNode; label: string; value: React.ReactNode }> = ({ icon, label, value }) => (
    <Box sx={{ display: 'flex', alignItems: 'flex-start', gap: 1, py: 0.5 }}>
        <Box sx={{ color: 'action.active', display: 'flex', flexShrink: 0, mt: '2px' }}>{icon}</Box>
        <Box sx={{ minWidth: 0 }}>
            <Typography variant="caption" color="text.secondary" sx={{ display: 'block', lineHeight: 1.2 }}>
                {label}
            </Typography>
            <Typography variant="body2" component="div" sx={{ wordBreak: 'break-word' }}>
                {value || '—'}
            </Typography>
        </Box>
    </Box>
);

const formatDateTime = (dt: number | string | undefined): string => {
    if (dt === undefined || dt === null || dt === '') return '—';
    try {
        return new Date(dt).toLocaleString();
    } catch {
        return String(dt);
    }
};

const isFullProfile = (profile: PublicProfileResult | ProfileResult): profile is ProfileResult => {
    return 'createdAt' in profile;
};

const GuidLink: React.FC<{ value: string | undefined; label?: string; mode: ProfileInfoMode }> = ({ value, label, mode }) => {
    const [open, setOpen] = useState(false);
    if (!value) return <>—</>;
    const isGuid = Validator.IsGuid(value);
    const displayText = label || value;

    if (!isGuid) return <>{displayText}</>;

    return (
        <>
            <Box
                component="span"
                onClick={() => setOpen(true)}
                sx={{ cursor: 'pointer', color: 'primary.main', '&:hover': { textDecoration: 'underline' }, display: 'inline-flex', alignItems: 'center', gap: 0.5 }}
            >
                {displayText}
                <LinkIcon sx={{ fontSize: '0.85rem' }} />
            </Box>
            <ProfileInfoDialog open={open} profileId={value} mode={mode} onClose={() => setOpen(false)} />
        </>
    );
};

export const ProfileInfoDialog: React.FC<ProfileInfoDialogProps> = ({ open, profileId, mode, onClose }) => {
    const [profile, setProfile] = useState<PublicProfileResult | ProfileResult | null>(null);
    const [status, setStatus] = useState<CallStatus>(CallStatus.NotStarted);
    const [error, setError] = useState<string>('');
    const [isDeleteDialogOpen, setIsDeleteDialogOpen] = useState(false);
    const [isDeleting, setIsDeleting] = useState(false);
    const [isRoleDialogOpen, setIsRoleDialogOpen] = useState(false);
    const [isResetDialogOpen, setIsResetDialogOpen] = useState(false);
    const [isResetting, setIsResetting] = useState(false);
    const [resetMessage, setResetMessage] = useState<{ severity: 'success' | 'error'; text: string } | null>(null);
    const navigate = useNavigate();

    // Auto-promote to admin mode when the *caller* has Admin or SuperAdmin role,
    // so admin actions (Edit/Roles/Reset/Delete) appear consistently regardless
    // of which surface opened the dialog (search results, attendee row, role
    // list, etc.). Callers can still pass mode="public" to opt out.
    const callerRoles = GetUserRoles();
    const callerIsAdmin = callerRoles.includes(Roles.Admin) || callerRoles.includes(Roles.SuperAdmin);
    const isAdmin = mode === 'admin' || callerIsAdmin;
    const targetIsSuperAdmin = !!(profile && 'roles' in profile && profile.roles?.includes(Roles.SuperAdmin));
    const isSelf = !!(profile && GetUserId() === profile.id);
    const showActions = isAdmin && status === CallStatus.Success && !!profile;
    // Reset is allowed for any admin target (including self and SuperAdmin — server enforces SuperAdmin-only resets SuperAdmin).
    const showReset = showActions;
    // Delete is blocked for SuperAdmin targets and for self (no self-destruct).
    const showDelete = showActions && !targetIsSuperAdmin && !isSelf;
    // Roles cannot be edited for SuperAdmin targets nor for self.
    const showRoles = showActions && !targetIsSuperAdmin && !isSelf;
    const showEdit = showActions;

    useBodyScrollLock(open);

    useEffect(() => {
        if (!open || !profileId) return;

        setStatus(CallStatus.InProgress);
        setError('');
        setProfile(null);

        const fetchProfile = isAdmin
            ? ProfileServices.GetAdminProfileById(profileId)
            : ProfileServices.GetProfileById(profileId);

        fetchProfile
            .then((response) => {
                if (response.data.status >= 200 && response.data.status < 300) {
                    setProfile(response.data.result);
                    setStatus(CallStatus.Success);
                } else {
                    setError(ProfileServicesError.GetProfileByIdError(response.data.status));
                    setStatus(CallStatus.Failure);
                }
            })
            .catch((err: any) => {
                const httpStatus = err?.response?.status || 0;
                setError(ProfileServicesError.GetProfileByIdError(httpStatus));
                setStatus(CallStatus.Failure);
            });
    }, [open, profileId, isAdmin]);

    const handleEditClick = () => {
        if (profileId) {
            navigate({ to: '/profile/edit/$id', params: { id: profileId } });
            onClose();
        }
    };

    const handleDeleteClick = () => {
        setIsDeleteDialogOpen(true);
    };

    const handleResetClick = () => {
        setResetMessage(null);
        setIsResetDialogOpen(true);
    };

    const handleConfirmReset = async () => {
        if (!profileId) {
            setIsResetDialogOpen(false);
            return;
        }
        setIsResetting(true);
        try {
            const response = await AuthServices.AdminReset(profileId);
            const status = response?.data?.status ?? 0;
            if (status >= 200 && status < 300) {
                setResetMessage({ severity: 'success', text: `Auth reset for ${profile?.name || profileId}. They will need to login again and re-setup the authenticator.` });
            } else {
                setResetMessage({ severity: 'error', text: AuthServicesError.ResetAuthError(status) });
            }
        } catch (err) {
            const info = getApiError(err);
            logger.error('ProfileInfoDialog', 'Reset auth error', err);
            setResetMessage({ severity: 'error', text: AuthServicesError.ResetAuthError(info.httpStatus) });
        } finally {
            setIsResetting(false);
            setIsResetDialogOpen(false);
        }
    };

    const handleConfirmDelete = async () => {
        if (!profileId) return;
        
        setIsDeleting(true);
        try {
            const response = await ProfileServices.DeleteProfileAdmin(profileId);
            if (response.data.status >= 200 && response.data.status < 300) {
                setIsDeleteDialogOpen(false);
                onClose();
            } else {
                alert(`Error deleting profile: ${response.data.message || 'Unknown error'}`);
            }
        } catch (err) {
            const info = getApiError(err);
            logger.error('ProfileInfoDialog', 'Delete error', err);
            alert(`Error deleting profile: ${info.message ?? 'Unknown error'}`);
        } finally {
            setIsDeleting(false);
        }
    };

    // Determine what to show based on mode and visibility flags
    const showContact = isAdmin || (profile?.isContactInfoVisible ?? false);
    const showEmployment = isAdmin || (profile?.isEmploymentInfoVisible ?? false);
    const showEducation = isAdmin || (profile?.isHigherEducationInfoVisible ?? false);

    return (
        <Dialog open={open} onClose={onClose} maxWidth="sm" fullWidth>
            <DialogTitle sx={{ display: 'flex', alignItems: 'center', pr: 14 }}>
                <Box sx={{ display: 'flex', alignItems: 'center', gap: 1, flexGrow: 1 }}>
                    <PersonIcon color="primary" />
                    Profile Details
                </Box>
                <Stack direction="row" spacing={0.5} sx={{ position: 'absolute', right: 48, top: 12 }}>
                    {showDelete && (
                        <IconButton 
                            onClick={handleDeleteClick} 
                            color="error" 
                            size="small"
                            title="Delete Profile"
                            aria-label="Delete profile"
                        >
                            <DeleteIcon />
                        </IconButton>
                    )}
                    {showReset && (
                        <IconButton
                            onClick={handleResetClick}
                            color="warning"
                            size="small"
                            title="Reset Auth"
                            aria-label="Reset auth"
                        >
                            <LockResetIcon />
                        </IconButton>
                    )}
                    {showRoles && (
                        <IconButton
                            onClick={() => setIsRoleDialogOpen(true)}
                            color="primary"
                            size="small"
                            title="Manage Roles"
                            aria-label="Manage roles"
                        >
                            <AdminPanelSettingsIcon />
                        </IconButton>
                    )}
                    {showEdit && (
                        <IconButton
                            onClick={handleEditClick}
                            color="primary"
                            size="small"
                            title="Edit Profile"
                            aria-label="Edit profile"
                        >
                            <EditIcon />
                        </IconButton>
                    )}
                </Stack>
                <IconButton onClick={onClose} sx={{ position: 'absolute', right: 8, top: 8 }} aria-label="Close dialog">
                    <CloseIcon />
                </IconButton>
            </DialogTitle>
            <DialogContent dividers>
                {status === CallStatus.InProgress && (
                    <Box sx={{ display: 'flex', justifyContent: 'center', py: 4 }}>
                        <CircularProgress />
                    </Box>
                )}

                {status === CallStatus.Failure && (
                    <Alert severity="error">{error}</Alert>
                )}

                {resetMessage && (
                    <Alert severity={resetMessage.severity} sx={{ mb: 1 }} onClose={() => setResetMessage(null)}>
                        {resetMessage.text}
                    </Alert>
                )}

                {status === CallStatus.Success && profile && (
                    <Box sx={{ display: 'flex', flexDirection: 'column', gap: 0.5 }}>
                        {/* Basic Info */}
                        <Typography variant="overline" color="primary" sx={{ mt: 0.5 }}>Basic Information</Typography>
                        <DetailRow icon={<PersonIcon sx={{ fontSize: '1rem' }} />} label="Name" value={profile.name} />
                        <DetailRow icon={<BadgeIcon sx={{ fontSize: '1rem' }} />} label="Gender" value={profile.gender} />
                        <DetailRow icon={<BadgeIcon sx={{ fontSize: '1rem' }} />} label="Profile Type" value={profile.profileType} />
                        <DetailRow icon={<BadgeIcon sx={{ fontSize: '1rem' }} />} label="Batch" value={profile.batch > 0 ? profile.batch : '—'} />
                        <DetailRow icon={<BadgeIcon sx={{ fontSize: '1rem' }} />} label="Entry" value={profile.entryYear > 0 ? `${profile.entryYear} (Class ${profile.entryClass})` : '—'} />
                        <DetailRow icon={<BadgeIcon sx={{ fontSize: '1rem' }} />} label="Exit" value={profile.exitYear > 0 ? `${profile.exitYear} (Class ${profile.exitClass})` : '—'} />

                        <Divider sx={{ my: 1 }} />

                        {/* School */}
                        <Typography variant="overline" color="primary">School</Typography>
                        <DetailRow icon={<LocalLibraryIcon sx={{ fontSize: '1rem' }} />} label="First JNV" value={profile.firstJnvName} />
                        {profile.otherJnvNames && (
                            <DetailRow icon={<LocalLibraryIcon sx={{ fontSize: '1rem' }} />} label="Other JNVs" value={profile.otherJnvNames} />
                        )}

                        {/* Contact — shown always for admin, respects flag for public */}
                        {showContact && (
                            <>
                                <Divider sx={{ my: 1 }} />
                                <Typography variant="overline" color="primary">Contact</Typography>
                                <DetailRow icon={<EmailIcon sx={{ fontSize: '1rem' }} />} label="Email" value={profile.email} />
                                <DetailRow icon={<PhoneIcon sx={{ fontSize: '1rem' }} />} label="Phone" value={profile.phone} />
                                <DetailRow icon={<PlaceIcon sx={{ fontSize: '1rem' }} />} label="Location" value={profile.location} />
                                {isAdmin && isFullProfile(profile) && (
                                    <DetailRow icon={<LocationOnIcon sx={{ fontSize: '1rem' }} />} label="Coordinates" value={
                                        profile.latitude && profile.longitude
                                            ? `${profile.latitude.toFixed(4)}, ${profile.longitude.toFixed(4)}`
                                            : '—'
                                    } />
                                )}
                                {isAdmin && (
                                    <DetailRow icon={<BadgeIcon sx={{ fontSize: '1rem' }} />} label="Contact Visible" value={profile.isContactInfoVisible ? 'Yes' : 'No'} />
                                )}
                            </>
                        )}

                        {/* Employment — shown always for admin, respects flag for public */}
                        {showEmployment && (
                            <>
                                <Divider sx={{ my: 1 }} />
                                <Typography variant="overline" color="primary">Employment</Typography>
                                <DetailRow icon={<WorkIcon sx={{ fontSize: '1rem' }} />} label="organisation" value={profile.organisation} />
                                <DetailRow icon={<WorkIcon sx={{ fontSize: '1rem' }} />} label="Job Title" value={profile.jobTitle} />
                                {isAdmin && (
                                    <>
                                        <DetailRow icon={<BadgeIcon sx={{ fontSize: '1rem' }} />} label="Currently Working" value={profile.isWorking ? 'Yes' : 'No'} />
                                        <DetailRow icon={<BadgeIcon sx={{ fontSize: '1rem' }} />} label="Employment Visible" value={profile.isEmploymentInfoVisible ? 'Yes' : 'No'} />
                                    </>
                                )}
                            </>
                        )}

                        {/* Education — shown always for admin, respects flag for public */}
                        {showEducation && (
                            <>
                                <Divider sx={{ my: 1 }} />
                                <Typography variant="overline" color="primary">Education</Typography>
                                <DetailRow icon={<SchoolIcon sx={{ fontSize: '1rem' }} />} label="University" value={profile.university} />
                                <DetailRow icon={<SchoolIcon sx={{ fontSize: '1rem' }} />} label="Degree" value={profile.degree} />
                                {isAdmin && (
                                    <>
                                        <DetailRow icon={<BadgeIcon sx={{ fontSize: '1rem' }} />} label="Currently Studying" value={profile.isStudying ? 'Yes' : 'No'} />
                                        <DetailRow icon={<BadgeIcon sx={{ fontSize: '1rem' }} />} label="Education Visible" value={profile.isHigherEducationInfoVisible ? 'Yes' : 'No'} />
                                    </>
                                )}
                            </>
                        )}

                        {/* Admin-only sections */}
                        {isAdmin && isFullProfile(profile) && (
                            <>
                                <Divider sx={{ my: 1 }} />
                                <Typography variant="overline" color="primary">Roles</Typography>
                                <DetailRow icon={<SecurityIcon sx={{ fontSize: '1rem' }} />} label="Roles" value={
                                    profile.roles && profile.roles.length > 0
                                        ? <Stack direction="row" sx={{ flexWrap: 'wrap', gap: 0.5 }}>{profile.roles.map((r, i) => <Chip key={i} label={r} size="small" sx={{ borderRadius: 1, height: 20, fontSize: '0.7rem' }} />)}</Stack>
                                        : '—'
                                } />

                                <Divider sx={{ my: 1 }} />
                                <Typography variant="overline" color="primary">Audit</Typography>
                                <DetailRow icon={<BadgeIcon sx={{ fontSize: '1rem' }} />} label="User ID" value={profile.id} />
                                <DetailRow icon={<CalendarTodayIcon sx={{ fontSize: '1rem' }} />} label="Created At" value={formatDateTime(profile.createdAt)} />
                                <DetailRow icon={<PersonIcon sx={{ fontSize: '1rem' }} />} label="Created By" value={
                                    profile.createdBy === profile.id ? 'Self'
                                        : <GuidLink value={profile.createdBy} label={profile.createdByName || profile.createdBy} mode={mode} />
                                } />
                                <DetailRow icon={<EditIcon sx={{ fontSize: '1rem' }} />} label="Modified At" value={formatDateTime(profile.modifiedAt)} />
                                <DetailRow icon={<PersonIcon sx={{ fontSize: '1rem' }} />} label="Modified By" value={
                                    profile.modifiedBy === profile.id ? 'Self'
                                        : <GuidLink value={profile.modifiedBy} mode={mode} />
                                } />
                            </>
                        )}
                    </Box>
                )}
            </DialogContent>
            
            {/* Delete Confirmation Dialog */}
            <ConfirmDialog
                open={isDeleteDialogOpen}
                onCancel={() => setIsDeleteDialogOpen(false)}
                onConfirm={handleConfirmDelete}
                title="Confirm Delete"
                description={
                    <Typography>
                        Are you sure you want to delete the profile of <Box component="span" sx={{ fontWeight: 'bold' }}>{profile?.name || 'this user'}</Box>?
                        This action cannot be undone.
                    </Typography>
                }
                confirmLabel="Delete"
                tone="error"
                busy={isDeleting}
                busyLabel="Deleting..."
            />

            {/* Reset Auth Confirmation Dialog */}
            <ConfirmDialog
                open={isResetDialogOpen}
                onCancel={() => setIsResetDialogOpen(false)}
                onConfirm={handleConfirmReset}
                title="Reset Authentication"
                description={
                    <Typography>
                        Reset auth for <Box component="span" sx={{ fontWeight: 'bold' }}>{profile?.name || 'this user'}</Box>?
                        They will be logged out from all devices and must re-setup their authenticator app.
                    </Typography>
                }
                confirmLabel="Reset"
                tone="warning"
                busy={isResetting}
                busyLabel="Resetting..."
            />

            {/* Manage Roles Dialog */}
            {isAdmin && profile && (
                <UpdateRoleDialog
                    open={isRoleDialogOpen}
                    profile={{
                        id: profile.id,
                        name: profile.name,
                        roles: 'roles' in profile ? profile.roles : undefined,
                    } as RoleDialogProfile}
                    onClose={() => setIsRoleDialogOpen(false)}
                    onSuccess={(updated: RoleDialogProfile) => {
                        if (profile && 'roles' in profile) {
                            setProfile({ ...(profile as ProfileResult), roles: updated.roles });
                        }
                        setIsRoleDialogOpen(false);
                    }}
                />
            )}
        </Dialog>
    );
};
