import React, { useState, useEffect } from 'react';
import {
    Button,
    Stack,
    Alert,
    CircularProgress,
    Box,
    Typography,
    Chip,
    Switch,
} from '@mui/material';
import SecurityIcon from '@mui/icons-material/Security';
import AdminPanelSettingsIcon from '@mui/icons-material/AdminPanelSettings';
import SchoolIcon from '@mui/icons-material/School';
import GroupsIcon from '@mui/icons-material/Groups';
import EventIcon from '@mui/icons-material/Event';
import PersonIcon from '@mui/icons-material/Person';
import { Roles } from '@/types/api.types';
import { ProfileServices } from '@/api/profiles.api';
import { compactChipSx } from '@/constants/ThemeConstants';
import { useBodyScrollLock } from '@/hooks/useBodyScrollLock';
import { getApiError } from '@/utils/apiError';
import { AppDialog } from '@/components/ui/AppDialog';

export type RoleDialogProfile = {
    id: string;
    name?: string;
    roles?: Roles[];
};

interface UpdateRoleDialogProps {
    open: boolean;
    profile: RoleDialogProfile | null;
    onClose: () => void;
    onSuccess: (updatedProfile: RoleDialogProfile) => void;
}

const AVAILABLE_ROLES = [
    Roles.SuperAdmin,
    Roles.Admin,
    Roles.SchoolAdmin,
    Roles.BatchAdmin,
    Roles.EventMgr,
    Roles.User,
];

const roleConfig: Record<string, { icon: React.ReactNode; description: string; color: string }> = {
    [Roles.SuperAdmin]: { icon: <SecurityIcon sx={{ fontSize: '1.2rem' }} />, description: 'Full system access, cannot be modified', color: '#9c27b0' },
    [Roles.Admin]: { icon: <AdminPanelSettingsIcon sx={{ fontSize: '1.2rem' }} />, description: 'Manage users, roles, and settings', color: '#9c27b0' },
    [Roles.SchoolAdmin]: { icon: <SchoolIcon sx={{ fontSize: '1.2rem' }} />, description: 'Manage school-specific data', color: '#0288d1' },
    [Roles.BatchAdmin]: { icon: <GroupsIcon sx={{ fontSize: '1.2rem' }} />, description: 'Manage batch-specific data', color: '#0288d1' },
    [Roles.EventMgr]: { icon: <EventIcon sx={{ fontSize: '1.2rem' }} />, description: 'Create and manage events', color: '#0288d1' },
    [Roles.User]: { icon: <PersonIcon sx={{ fontSize: '1.2rem' }} />, description: 'Standard user access', color: '#9e9e9e' },
};

const UpdateRoleDialog: React.FC<UpdateRoleDialogProps> = ({ open, profile, onClose, onSuccess }) => {
    const [selectedRoles, setSelectedRoles] = useState<string[]>([]);
    const [isSubmitting, setIsSubmitting] = useState(false);
    const [error, setError] = useState<string | null>(null);

    useBodyScrollLock(open);

    useEffect(() => {
        if (profile) {
            setSelectedRoles((profile.roles || []).filter(r => AVAILABLE_ROLES.includes(r as Roles)));
            setError(null);
        }
    }, [profile, open]);

    const isSuperAdmin = selectedRoles.includes(Roles.SuperAdmin);

    const handleRoleToggle = (role: string) => {
        // Prevent toggling SuperAdmin
        if (role === Roles.SuperAdmin) {
            return;
        }
        // Admin role cannot be removed from a SuperAdmin user
        if (role === Roles.Admin && isSuperAdmin) {
            return;
        }
        
        setSelectedRoles(prev => {
            if (prev.includes(role)) {
                const updated = prev.filter(r => r !== role);
                // Removing User role removes all roles (suspension)
                if (role === Roles.User) {
                    return [];
                }
                return updated;
            } else {
                // Adding any role also ensures User role is present
                if (role === Roles.User) {
                    return [...prev, role];
                }
                if (!prev.includes(Roles.User)) {
                    return [...prev, role, Roles.User];
                }
                return [...prev, role];
            }
        });
    };

    const handleSave = async () => {
        if (!profile) return;

        setIsSubmitting(true);
        setError(null);

        try {
            const response = await ProfileServices.UpdateUserRoles(profile.id, selectedRoles);

            if (response.data.status === 200 && response.data.result) {
                // Update the profile with new roles
                const updatedProfile: RoleDialogProfile = {
                    ...profile,
                    roles: selectedRoles as any[],
                };
                onSuccess(updatedProfile);
            } else {
                setError('Failed to update roles. Please try again.');
            }
        } catch (err) {
            const info = getApiError(err);
            setError(info.message || 'An error occurred while updating roles. Please try again.');
        } finally {
            setIsSubmitting(false);
        }
    };

    if (!profile) return null;

    // Compare role sets without serialization: same length and every selected role present in original.
    const originalRoles = profile.roles || [];
    const hasChanges =
        selectedRoles.length !== originalRoles.length ||
        selectedRoles.some(r => !(originalRoles as string[]).includes(r));

    return (
        <AppDialog
            open={open}
            onClose={onClose}
            maxWidth="xs"
            busy={isSubmitting}
            title={
                <Stack spacing={0.25}>
                    <Typography component="span" variant="h6" sx={{ lineHeight: 1.2 }}>Edit Roles</Typography>
                    <Typography variant="body2" sx={{ color: 'text.secondary', fontWeight: 500 }}>
                        {profile.name}
                    </Typography>
                    <Typography variant="caption" sx={{ color: 'text.disabled' }}>
                        {profile.id}
                    </Typography>
                </Stack>
            }
            actions={
                <>
                    <Button onClick={onClose} disabled={isSubmitting} size="small">
                        Cancel
                    </Button>
                    <Button
                        onClick={handleSave}
                        variant="contained"
                        size="small"
                        disabled={isSubmitting || !hasChanges}
                        startIcon={isSubmitting ? <CircularProgress size={16} /> : undefined}
                    >
                        {isSubmitting ? 'Saving...' : 'Save Changes'}
                    </Button>
                </>
            }
        >
            {error && (
                <Alert severity="error" sx={{ mb: 1.5 }}>
                    {error}
                </Alert>
            )}

            <Stack spacing={0}>
                {AVAILABLE_ROLES.map(role => {
                    const config = roleConfig[role];
                    const isActive = selectedRoles.includes(role);
                    const isDisabled = isSubmitting || role === Roles.SuperAdmin || (role === Roles.Admin && isSuperAdmin);
                    return (
                        <Box
                            key={role}
                            onClick={() => !isDisabled && handleRoleToggle(role)}
                            sx={{
                                display: 'flex',
                                alignItems: 'center',
                                gap: 1.5,
                                px: 1.5,
                                py: 1,
                                borderRadius: 1.5,
                                cursor: isDisabled ? 'default' : 'pointer',
                                opacity: isDisabled ? 0.55 : 1,
                                transition: 'background-color 0.15s',
                                '&:hover': !isDisabled ? { bgcolor: 'action.hover' } : undefined,
                            }}
                        >
                            <Box sx={{ color: isActive ? config.color : 'text.disabled', display: 'flex', alignItems: 'center' }}>
                                {config.icon}
                            </Box>
                            <Box sx={{ flex: 1, minWidth: 0 }}>
                                <Typography variant="body2" sx={{ fontWeight: 500, color: isActive ? 'text.primary' : 'text.secondary' }}>
                                    {role}
                                </Typography>
                                <Typography variant="caption" sx={{ color: 'text.disabled', lineHeight: 1.2 }}>
                                    {config.description}
                                </Typography>
                            </Box>
                            <Switch
                                size="small"
                                checked={isActive}
                                disabled={isDisabled}
                                onClick={(e) => e.stopPropagation()}
                                onChange={() => handleRoleToggle(role)}
                                sx={{
                                    '& .MuiSwitch-switchBase.Mui-checked': { color: config.color },
                                    '& .MuiSwitch-switchBase.Mui-checked + .MuiSwitch-track': { backgroundColor: config.color },
                                }}
                            />
                        </Box>
                    );
                })}
            </Stack>

            {selectedRoles.length === 0 && (
                <Alert severity="warning" sx={{ mt: 1.5, fontSize: '0.8rem' }}>
                    No roles assigned. User will be suspended.
                </Alert>
            )}

            {hasChanges && (
                <Box sx={{ mt: 1.5 }}>
                    <Typography variant="caption" sx={{ color: 'text.disabled', mb: 0.5, display: 'block' }}>
                        Updated roles:
                    </Typography>
                    <Stack direction="row" spacing={0.5} sx={{ flexWrap: 'wrap', gap: 0.5 }}>
                        {selectedRoles.map(role => (
                            <Chip
                                key={role}
                                label={role}
                                size="small"
                                sx={{
                                    ...compactChipSx,
                                    bgcolor: roleConfig[role]?.color || '#9e9e9e',
                                    color: '#fff !important',
                                    '& .MuiChip-label': { color: '#fff' },
                                }}
                            />
                        ))}
                    </Stack>
                </Box>
            )}
        </AppDialog>
    );
};

export default UpdateRoleDialog;
